	private static final class CountingStatementSource extends StubSketchStatementSource {
		private final AtomicInteger lookupCalls = new AtomicInteger();

		@Override
		public CloseableIteration<? extends Statement> getStatements(Resource subj, IRI pred, Value obj,
				Resource... contexts) {
			lookupCalls.incrementAndGet();
			return super.getStatements(subj, pred, obj, contexts);
		}

		private int lookupCalls() {
			return lookupCalls.get();
		}

		private void resetLookupCalls() {
			lookupCalls.set(0);
		}
	}

